script:
frappe.ui.form.on('taq_data1', {
    validate: function(frm) {
        if (frm.doc.agee && frm.doc.agee < 23) {
            frappe.throw(__('يجب أن لا يكون عمر الواعظ أقل من 23 عام'));
        }
    },
    agee: function(frm) {
        if (frm.doc.agee && frm.doc.agee < 23) {
            frappe.msgprint(__('يجب أن لا يكون عمر الواعظ أقل من 23 عام'));
            frm.set_value('agee', '');  // يمسح العمر المدخل
        }
    }
});

frappe.ui.form.on('exam_group_date', {
    get_preachers: function(frm) {
        frm.call('get_preachers').then(r => {
            let rows = frm.doc.waed_info_to_exam || [];

            // تفعيل fetch_from يدويًا لكل صف، كأنه تم اختياره من المستخدم
            let promises = rows.map(row => {
                return frappe.model.set_value(row.doctype, row.name, 'waed_info', row.waed_info);
            });

            Promise.all(promises).then(() => {
                frm.refresh_field('waed_info_to_exam');
                frm.refresh_field('count_waes_exam');
                frappe.show_alert({
                    message: __('تم جلب {0} واعظ بنجاح', [rows.length]),
                    indicator: 'green'
                });
            });
        });
    }
});

frappe.ui.form.on('exam_group_date', {
    count_to_exam(frm) {
        const count = frm.doc.count_to_exam;

        if (count <= 0 || count > 30) {
            frappe.msgprint({
                title: __('تنبيه'),
                indicator: 'red',
                message: __('يجب أن يكون عدد المتقدمين بين 1 و 30')
            });

            frm.set_value('count_to_exam', null);
        }
    },

    validate(frm) {
        const count = frm.doc.count_to_exam;

        if (count <= 0 || count > 30) {
            frappe.throw(__('يجب أن يكون عدد المتقدمين بين 1 و 30'));
        }
    }
});

frappe.ui.form.on('lag_user_name_child', {
    the_adjective(frm, cdt, cdn) {

        let row = locals[cdt][cdn];

        if (!row.the_adjective) return;

        let count = (frm.doc.committee_members || []).filter(
            d => d.the_adjective === row.the_adjective
        ).length;

        if (
            ["رئيس لجنة", "مقرر"].includes(row.the_adjective)
            && count > 1
        ) {
            frappe.msgprint(
                __("لا يمكن إضافة أكثر من {0}", [row.the_adjective])
            );

            frappe.model.set_value(
                cdt,
                cdn,
                "the_adjective",
                ""
            );
        }
    }
});


frappe.ui.form.on('exam_lag_data', {
    validate(frm) {

        let chairman_count = 0;
        let secretary_count = 0;
        let member_count = 0;

        let users = [];

        (frm.doc.committee_members || []).forEach(row => {

            // عد رئيس اللجنة
            if (row.the_adjective === "رئيس لجنة") {
                chairman_count++;
            }

            // عد المقرر
            if (row.the_adjective === "مقرر") {
                secretary_count++;
            }

            // عد الأعضاء
            if (row.the_adjective === "عضو") {
                member_count++;
            }

            // منع تكرار نفس العضو
            if (row.user_name) {

                if (users.includes(row.user_name)) {
                    frappe.throw(
                        __("تم اختيار العضو {0} أكثر من مرة", [row.user_name])
                    );
                }

                users.push(row.user_name);
            }
        });

        // منع تعدد رئيس اللجنة
        if (chairman_count > 1) {
            frappe.throw(__("لا يمكن إضافة أكثر من رئيس لجنة واحد"));
        }

        // منع تعدد المقرر
        if (secretary_count > 1) {
            frappe.throw(__("لا يمكن إضافة أكثر من مقرر واحد"));
        }

        // التحقق من الحد الأدنى لتكوين اللجنة
        let missing = [];

        if (chairman_count < 1) {
            missing.push("رئيس لجنة");
        }

        if (secretary_count < 1) {
            missing.push("مقرر");
        }

        if (member_count < 1) {
            missing.push("عضو واحد علي الاقل");
        }

        if (missing.length) {
            frappe.throw(
                __("يجب أن تتكون اللجنة من: {0}", [missing.join("، ")])
            );
        }
    }
});
